function getStatusTone(isError) {
    return isError ? 'error' : 'info';
}

function getToastLabel(tone) {
    if (tone === 'error') return 'Ошибка';
    if (tone === 'success') return 'Готово';
    return 'Статус';
}

function removeToast(toast) {
    if (!toast || toast.dataset.hiding === '1') return;
    toast.dataset.hiding = '1';
    toast.classList.remove('is-visible');
    toast.classList.add('is-hiding');
    window.setTimeout(() => {
        toast.remove();
    }, 220);
}

function createToast(message, tone, duration) {
    if (!NotificationStack || !message) return;

    const toast = document.createElement('article');
    toast.className = `toast-notification is-${tone}`;

    const body = document.createElement('div');
    body.className = 'toast-body';

    const label = document.createElement('div');
    label.className = 'toast-label';
    label.textContent = getToastLabel(tone);

    const text = document.createElement('div');
    text.className = 'toast-message';
    text.textContent = message;

    const close = document.createElement('button');
    close.className = 'toast-close';
    close.type = 'button';
    close.setAttribute('aria-label', 'Скрыть уведомление');
    close.textContent = '×';
    close.addEventListener('click', () => removeToast(toast));

    const progress = document.createElement('div');
    progress.className = 'toast-progress';
    progress.style.animationDuration = `${duration}ms`;

    body.append(label, text);
    toast.append(body, close, progress);
    NotificationStack.prepend(toast);

    while (NotificationStack.children.length > 4) {
        NotificationStack.lastElementChild?.remove();
    }

    window.requestAnimationFrame(() => {
        toast.classList.add('is-visible');
    });

    window.setTimeout(() => removeToast(toast), duration);
}

function setStatus(message, isError = false, options = {}) {
    const tone = options.tone || getStatusTone(isError);
    const toastTone = tone === 'error' ? 'error' : (tone === 'success' ? 'success' : 'info');
    const shouldToast = options.toast !== false;
    const duration = Number.isFinite(options.duration) ? options.duration : (toastTone === 'error' ? 5200 : 3600);

    if (UploadStatus) {
        const row = UploadStatus.closest('.status-row');
        UploadStatus.textContent = message;
        if (row) {
            row.classList.remove('is-info', 'is-success', 'is-error');
            row.classList.add(`is-${toastTone}`);
        }
    }

    if (shouldToast) {
        createToast(message, toastTone, duration);
    }
}

function setSuccessStatus(message, options = {}) {
    setStatus(message, false, { ...options, tone: 'success' });
}

function setErrorStatus(message, options = {}) {
    setStatus(message, true, { ...options, tone: 'error' });
}

function setInfoStatus(message, options = {}) {
    setStatus(message, false, { ...options, tone: 'info' });
}

function setInitialStatus(message) {
    UploadStatus.textContent = message;
    const row = UploadStatus.closest('.status-row');
    if (row) {
        row.classList.remove('is-info', 'is-success', 'is-error');
        row.classList.add('is-info');
    }
}

function setSendBusy(isBusy) {
    if (!SendButton) return;
    SendButton.disabled = isBusy;
    SendButton.textContent = isBusy ? 'Отправка...' : 'Отправить на рамку';
}

function setLibraryBusy(isBusy) {
    if (!SaveLibraryButton) return;
    SaveLibraryButton.disabled = isBusy;
    SaveLibraryButton.textContent = isBusy ? 'Сохранение...' : 'Сохранить в коллекцию';
}

function updateInputStageState(fileName = "") {
    const hasImage = Boolean(fileFlag && ImageSys && ImageSys.src && !/placeholder\.svg(?:$|\?)/.test(ImageSys.src));
    if (InputStage) InputStage.classList.toggle('is-empty', !hasImage);
    if (InputStageHint) InputStageHint.hidden = hasImage;
    if (InputFileLabel) InputFileLabel.textContent = fileName || (hasImage ? 'Готово к обработке' : 'До обработки');
    if (InPutButton) InPutButton.textContent = hasImage ? 'Заменить фото' : 'Выбрать фото';
}

function setText(id, value) {
    const el = document.getElementById(id);
    if (el) el.textContent = value;
}

function showScreen(screenName) {
    const nextScreen = screenName || "prepare";
    if (appNavButtons) {
        appNavButtons.forEach(button => {
            button.classList.toggle('active', button.dataset.screen === nextScreen);
        });
    }
    if (appScreens) {
        appScreens.forEach(screen => {
            screen.classList.toggle('active', screen.dataset.screenPanel === nextScreen);
        });
    }
    window.scrollTo({ top: 0, behavior: 'smooth' });
}

function bindAppNavEvents() {
    if (!appNavButtons) return;
    appNavButtons.forEach(button => {
        button.addEventListener('click', function () {
            showScreen(this.dataset.screen);
            if (this.dataset.screen === "collection") {
                loadLibrary();
            } else if (this.dataset.screen === "settings" && DeviceStatusPanel && DeviceStatusPanel.open) {
                loadDeviceStatus();
            }
        });
    });
}

function formatBytes(bytes) {
    if (!Number.isFinite(bytes) || bytes <= 0) return '0 Б';
    if (bytes < 1024) return `${bytes} Б`;
    if (bytes < 1024 * 1024) return `${Math.round(bytes / 1024)} КБ`;
    return `${(bytes / 1024 / 1024).toFixed(1)} МБ`;
}

function drawThumbnailToCanvas(img) {
    const maxSide = 420;
    const scale = Math.min(maxSide / img.naturalWidth, maxSide / img.naturalHeight, 1);
    const canvas = document.createElement('canvas');
    canvas.width = Math.max(1, Math.round(img.naturalWidth * scale));
    canvas.height = Math.max(1, Math.round(img.naturalHeight * scale));
    const ctx = canvas.getContext('2d');
    ctx.imageSmoothingEnabled = true;
    ctx.imageSmoothingQuality = 'high';
    ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    return canvas;
}

function updatePlaylistLastLabel() {
    if (!PlaylistLastLabel) return;
    PlaylistLastLabel.textContent = playlistLast || 'не выбрана';
    PlaylistLastLabel.classList.toggle('is-empty', !playlistLast);
}

function isUsableLibraryImageName(name) {
    return typeof name === 'string' && name.length > 0 && !name.startsWith('.') && !name.startsWith('._');
}

function resetThumbQueues() {
    thumbLoadGeneration++;
    thumbLoadQueue = [];
    thumbLoadActive = 0;
    thumbRepairQueue = [];
    thumbRepairActive = false;
    thumbRepairQueued.clear();
}

function fetchWithTimeout(url, options = {}, timeoutMs = 10000) {
    if (!('AbortController' in window)) {
        return fetch(url, options);
    }
    const controller = new AbortController();
    const timeout = window.setTimeout(() => controller.abort(), timeoutMs);
    return fetch(url, { ...options, signal: controller.signal })
        .finally(() => window.clearTimeout(timeout));
}

function setThumbLoading(preview, isLoading) {
    if (!preview) return;
    preview.classList.toggle('is-loading', isLoading);
    if (preview.parentElement) {
        preview.parentElement.classList.toggle('is-loading', isLoading);
    }
}

function processThumbLoadQueue() {
    const maxActive = 1;
    while (thumbLoadActive < maxActive && thumbLoadQueue.length > 0) {
        const job = thumbLoadQueue.shift();
        const preview = job.preview;
        if (!preview || job.generation !== thumbLoadGeneration || preview.dataset.loadedThumb) {
            continue;
        }
        thumbLoadActive++;
        const finish = () => {
            thumbLoadActive = Math.max(0, thumbLoadActive - 1);
            processThumbLoadQueue();
        };
        setThumbLoading(preview, true);
        fetchWithTimeout(preview.dataset.src, { cache: 'no-store' }, 45000)
            .then(response => {
                if (!response.ok) throw new Error(`thumb fetch failed: ${response.status}`);
                return response.blob();
            })
            .then(blob => {
                if (job.generation !== thumbLoadGeneration) return;
                const objectUrl = URL.createObjectURL(blob);
                preview.onload = () => {
                    URL.revokeObjectURL(objectUrl);
                    setThumbLoading(preview, false);
                };
                preview.onerror = () => {
                    URL.revokeObjectURL(objectUrl);
                    setThumbLoading(preview, false);
                    preview.classList.add('is-missing');
                };
                preview.src = objectUrl;
                preview.dataset.loadedThumb = '1';
                preview.classList.remove('is-missing');
            })
            .catch(error => {
                if (job.generation !== thumbLoadGeneration) return;
                console.warn('Thumbnail load failed:', error);
                queueThumbRepair(job.name, preview, job.generation);
            })
            .finally(finish);
    }
}

function queueThumbLoad(preview, name) {
    setThumbLoading(preview, true);
    thumbLoadQueue.push({ preview, name, generation: thumbLoadGeneration });
    processThumbLoadQueue();
}

function queueThumbRepair(name, preview, generation) {
    if (!name || !preview || preview.dataset.repairing || generation !== thumbLoadGeneration) {
        if (preview) {
            setThumbLoading(preview, false);
            preview.classList.add('is-missing');
        }
        return;
    }
    if (thumbRepairQueued.has(name)) {
        setThumbLoading(preview, false);
        preview.classList.add('is-missing');
        return;
    }
    thumbRepairQueued.add(name);
    thumbRepairQueue.push({ name, preview, generation });
    processThumbRepairQueue();
}

function processThumbRepairQueue() {
    if (thumbRepairActive || thumbRepairQueue.length === 0) return;
    const job = thumbRepairQueue.shift();
    if (job.generation !== thumbLoadGeneration) {
        thumbRepairQueued.delete(job.name);
        processThumbRepairQueue();
        return;
    }
    thumbRepairActive = true;
    repairMissingThumb(job.name, job.preview)
        .finally(() => {
            thumbRepairQueued.delete(job.name);
            thumbRepairActive = false;
            window.setTimeout(processThumbRepairQueue, 1200);
        });
}

function repairMissingThumb(name, preview) {
    if (!name || !preview || preview.dataset.repairing) return Promise.resolve();
    preview.dataset.repairing = '1';
    setThumbLoading(preview, true);
    preview.classList.add('is-repairing');
    preview.onload = null;
    preview.onerror = null;
    return fetchWithTimeout(`/AdminImage?name=${encodeURIComponent(name)}`, { cache: 'no-store' }, 22000)
        .then(response => {
            if (!response.ok) throw new Error(`image fetch failed: ${response.status}`);
            return response.blob();
        })
        .then(blob => {
            const objectUrl = URL.createObjectURL(blob);
            preview.onload = () => setThumbLoading(preview, false);
            preview.onerror = () => setThumbLoading(preview, false);
            preview.src = objectUrl;

            return new Promise(resolve => {
                const img = new window.Image();
                img.onload = function () {
                    const canvas = drawThumbnailToCanvas(img);
                    canvas.toBlob(function (thumbBlob) {
                        if (!thumbBlob) {
                            URL.revokeObjectURL(objectUrl);
                            resolve();
                            return;
                        }
                        fetchWithTimeout(`/AdminThumbUpload?name=${encodeURIComponent(name)}`, {
                            method: 'POST',
                            headers: { 'Content-Type': 'image/jpeg' },
                            body: thumbBlob
                        }, 15000).then(response => {
                            if (response.ok) {
                                preview.src = `/AdminThumb?name=${encodeURIComponent(name)}&t=${Date.now()}`;
                            }
                        }).catch(error => {
                            console.warn('Thumbnail repair upload failed:', error);
                        }).finally(() => {
                            URL.revokeObjectURL(objectUrl);
                            resolve();
                        });
                    }, 'image/jpeg', 0.88);
                };
                img.onerror = function () {
                    URL.revokeObjectURL(objectUrl);
                    preview.removeAttribute('src');
                    setThumbLoading(preview, false);
                    preview.classList.add('is-missing');
                    resolve();
                };
                img.src = objectUrl;
            });
        })
        .catch(error => {
            console.warn('Thumbnail repair failed:', error);
            preview.removeAttribute('src');
            setThumbLoading(preview, false);
            preview.classList.add('is-missing');
        })
        .finally(() => {
            setThumbLoading(preview, false);
            preview.classList.remove('is-repairing');
            delete preview.dataset.repairing;
        });
}

function hasExplicitPlaylistOrder() {
    return playlistExplicit || playlistDirty;
}

function getPlaylistPayload() {
    return hasExplicitPlaylistOrder() ? playlistOrder.filter(Boolean) : [];
}

function initializePlaylistFromVisibleImages() {
    if (hasExplicitPlaylistOrder()) return;
    playlistOrder = libraryImages.map(image => image.name).filter(name => isUsableLibraryImageName(name));
    playlistExplicit = playlistOrder.length > 0;
}

function addToPlaylistIfExplicit(name) {
    if (!name || !hasExplicitPlaylistOrder() || playlistOrder.includes(name)) return;
    playlistOrder.push(name);
    playlistDirty = true;
}

function sortLoadedImages(images) {
    if (!hasExplicitPlaylistOrder()) {
        return images.slice();
    }
    const indexMap = new Map(playlistOrder.map((name, index) => [name, index]));
    return images.map((image, sourceIndex) => ({ image, sourceIndex })).sort((a, b) => {
        const ai = indexMap.has(a.image.name) ? indexMap.get(a.image.name) : Number.MAX_SAFE_INTEGER;
        const bi = indexMap.has(b.image.name) ? indexMap.get(b.image.name) : Number.MAX_SAFE_INTEGER;
        if (ai !== bi) return ai - bi;
        return a.sourceIndex - b.sourceIndex;
    }).map(item => item.image);
}

function updateLibraryStats() {
    if (LibraryStats) {
        const shown = libraryImages.length;
        const totalText = `${libraryTotal} файлов · ${formatBytes(libraryTotalSize)}`;
        LibraryStats.textContent = shown < libraryTotal ? `${shown}/${totalText}` : totalText;
    }
    if (DeleteSelectedButton) {
        DeleteSelectedButton.disabled = selectedImages.size === 0;
        DeleteSelectedButton.textContent = selectedImages.size ? `Удалить выбранные (${selectedImages.size})` : 'Удалить выбранные';
    }
    if (LoadMoreButton) {
        LoadMoreButton.hidden = libraryOffset <= 0 || libraryImages.length >= libraryTotal;
        LoadMoreButton.disabled = libraryLoading;
    }
}

function createLibrarySkeletonRow() {
    const row = document.createElement('div');
    row.className = 'library-item library-item--skeleton';
    row.setAttribute('aria-busy', 'true');
    row.setAttribute('aria-hidden', 'true');

    const selectPh = document.createElement('div');
    selectPh.className = 'library-skeleton-check';

    const dragPh = document.createElement('div');
    dragPh.className = 'library-skeleton-drag';

    const shell = document.createElement('div');
    shell.className = 'library-preview-shell library-skeleton-thumb';

    const meta = document.createElement('div');
    meta.className = 'library-meta';
    const line1 = document.createElement('div');
    line1.className = 'library-skeleton-line library-skeleton-line--lg';
    const line2 = document.createElement('div');
    line2.className = 'library-skeleton-line library-skeleton-line--sm';
    meta.appendChild(line1);
    meta.appendChild(line2);

    const actions = document.createElement('div');
    actions.className = 'library-actions library-skeleton-actions';
    for (let i = 0; i < 5; i++) {
        const b = document.createElement('div');
        b.className = 'library-skeleton-btn';
        actions.appendChild(b);
    }

    row.appendChild(selectPh);
    row.appendChild(dragPh);
    row.appendChild(shell);
    row.appendChild(meta);
    row.appendChild(actions);
    return row;
}

function renderLibrarySkeleton(count) {
    if (!LibraryList || count <= 0) return;
    if (thumbObserver) {
        thumbObserver.disconnect();
        thumbObserver = null;
    }
    resetThumbQueues();
    LibraryList.innerHTML = '';
    const frag = document.createDocumentFragment();
    for (let i = 0; i < count; i++) frag.appendChild(createLibrarySkeletonRow());
    LibraryList.appendChild(frag);
}

function prependLibrarySkeleton(count) {
    if (!LibraryList || count <= 0) return;
    const frag = document.createDocumentFragment();
    for (let i = 0; i < count; i++) frag.appendChild(createLibrarySkeletonRow());
    LibraryList.insertBefore(frag, LibraryList.firstChild);
}

function removeLibrarySkeletonRows() {
    if (!LibraryList) return;
    LibraryList.querySelectorAll('.library-item--skeleton').forEach(el => el.remove());
}

function observePreview(preview, name) {
    preview.dataset.name = name;
    preview.dataset.src = `/AdminThumb?name=${encodeURIComponent(name)}`;
    if ('IntersectionObserver' in window) {
        if (!thumbObserver) {
            thumbObserver = new IntersectionObserver(entries => {
                entries.forEach(entry => {
                    if (!entry.isIntersecting) return;
                    const img = entry.target;
                    thumbObserver.unobserve(img);
                    queueThumbLoad(img, img.dataset.name);
                });
            }, { rootMargin: '48px' });
        }
        thumbObserver.observe(preview);
    } else {
        queueThumbLoad(preview, name);
    }
}

function renderLibrary(images = libraryImages, highlightName = "") {
    if (!LibraryList) return;
    libraryImages = sortLoadedImages(Array.isArray(images) ? images : []);
    LibraryList.innerHTML = '';
    if (thumbObserver) {
        thumbObserver.disconnect();
        thumbObserver = null;
    }
    resetThumbQueues();
    if (libraryImages.length === 0) {
        const empty = document.createElement('div');
        empty.className = 'empty-library';
        empty.textContent = libraryQuery ? 'Поиск ничего не нашёл.' : 'В папке mode 1 пока нет изображений.';
        LibraryList.appendChild(empty);
        updateLibraryStats();
        return;
    }

    libraryImages.forEach(image => {
        const row = document.createElement('div');
        row.className = 'library-item';
        row.dataset.name = image.name;
        if (image.name === highlightName) row.classList.add('is-highlighted');

        const select = document.createElement('input');
        select.className = 'library-select';
        select.type = 'checkbox';
        select.checked = selectedImages.has(image.name);
        select.addEventListener('change', function () {
            if (select.checked) selectedImages.add(image.name);
            else selectedImages.delete(image.name);
            updateLibraryStats();
        });

        const drag = document.createElement('button');
        drag.className = 'drag-handle';
        drag.type = 'button';
        drag.textContent = '↕';
        drag.title = 'Перетащить в плейлисте';
        drag.addEventListener('pointerdown', function (event) {
            startPlaylistDrag(event, image.name, row);
        });

        const previewShell = document.createElement('div');
        previewShell.className = 'library-preview-shell is-loading';
        const preview = document.createElement('img');
        preview.className = 'library-preview';
        preview.alt = '';
        preview.loading = 'lazy';
        observePreview(preview, image.name);
        previewShell.appendChild(preview);

        const meta = document.createElement('div');
        meta.className = 'library-meta';
        const name = document.createElement('div');
        name.className = 'library-name';
        name.textContent = image.name;
        if (image.name === playlistLast) {
            const lastBadge = document.createElement('span');
            lastBadge.className = 'last-image-badge';
            lastBadge.textContent = 'Последняя';
            name.appendChild(lastBadge);
        }
        const size = document.createElement('div');
        size.className = 'library-size';
        size.textContent = formatBytes(Number(image.size));
        meta.appendChild(name);
        meta.appendChild(size);

        const actions = document.createElement('div');
        actions.className = 'library-actions';
        const moveUp = document.createElement('button');
        moveUp.className = 'btn order-action';
        moveUp.type = 'button';
        moveUp.textContent = '↑';
        moveUp.title = 'Выше в плейлисте';
        moveUp.addEventListener('click', () => movePlaylistItem(image.name, -1));
        const moveDown = document.createElement('button');
        moveDown.className = 'btn order-action';
        moveDown.type = 'button';
        moveDown.textContent = '↓';
        moveDown.title = 'Ниже в плейлисте';
        moveDown.addEventListener('click', () => movePlaylistItem(image.name, 1));
        const startHere = document.createElement('button');
        startHere.className = 'btn start-here-action';
        startHere.type = 'button';
        startHere.textContent = 'Старт отсюда';
        startHere.addEventListener('click', () => saveLastImageConfig(image.name, false).then(() => setStatus(`Mode 1 стартует с ${image.name}.`)));
        const setNow = document.createElement('button');
        setNow.className = 'btn set-now-action';
        setNow.type = 'button';
        setNow.textContent = 'Установить сейчас';
        setNow.addEventListener('click', () => setLibraryImageNow(image.name, setNow));
        const remove = document.createElement('button');
        remove.className = 'btn delete-action';
        remove.type = 'button';
        remove.textContent = 'Удалить';
        remove.addEventListener('click', () => deleteLibraryImage(image.name));
        actions.appendChild(moveUp);
        actions.appendChild(moveDown);
        actions.appendChild(startHere);
        actions.appendChild(setNow);
        actions.appendChild(remove);

        row.appendChild(select);
        row.appendChild(drag);
        row.appendChild(previewShell);
        row.appendChild(meta);
        row.appendChild(actions);
        LibraryList.appendChild(row);
    });
    updateLibraryStats();
}

function scrollToLibraryImage(name) {
    if (!LibraryList || !name) return;
    window.setTimeout(() => {
        const safeName = window.CSS && CSS.escape ? CSS.escape(name) : name.replace(/"/g, '\\"');
        const row = LibraryList.querySelector(`[data-name="${safeName}"]`);
        if (!row) return;
        row.scrollIntoView({ behavior: 'smooth', block: 'center' });
        row.classList.add('is-highlighted');
        window.setTimeout(() => row.classList.remove('is-highlighted'), 2200);
    }, 120);
}

function moveNameInPlaylist(name, beforeName) {
    if (!name || name === beforeName) return;
    initializePlaylistFromVisibleImages();
    const copy = playlistOrder.filter(item => item !== name);
    const beforeIndex = beforeName ? copy.indexOf(beforeName) : -1;
    copy.splice(beforeIndex >= 0 ? beforeIndex : copy.length, 0, name);
    playlistOrder = copy;
    playlistDirty = true;
}

function movePlaylistItem(name, delta) {
    initializePlaylistFromVisibleImages();
    const index = playlistOrder.indexOf(name);
    if (index < 0) return;
    const nextIndex = index + delta;
    if (nextIndex < 0 || nextIndex >= playlistOrder.length) return;
    const copy = playlistOrder.slice();
    const [item] = copy.splice(index, 1);
    copy.splice(nextIndex, 0, item);
    playlistOrder = copy;
    playlistDirty = true;
    renderLibrary(libraryImages);
    setStatus('Порядок изменён. Нажмите «Сохранить порядок», чтобы записать на SD.');
}

function startPlaylistDrag(event, name, row) {
    if (!event.isPrimary) return;
    event.preventDefault();
    dragState = { name, row };
    row.classList.add('is-dragging');
    row.setPointerCapture(event.pointerId);
    row.addEventListener('pointermove', handlePlaylistDragMove);
    row.addEventListener('pointerup', finishPlaylistDrag, { once: true });
    row.addEventListener('pointercancel', finishPlaylistDrag, { once: true });
}

function handlePlaylistDragMove(event) {
    if (!dragState) return;
    const target = document.elementFromPoint(event.clientX, event.clientY)?.closest('.library-item');
    if (!target || target === dragState.row || !LibraryList.contains(target)) return;
    const before = event.clientY < target.getBoundingClientRect().top + target.offsetHeight / 2;
    LibraryList.insertBefore(dragState.row, before ? target : target.nextSibling);
}

function finishPlaylistDrag(event) {
    if (!dragState) return;
    dragState.row.releasePointerCapture?.(event.pointerId);
    dragState.row.classList.remove('is-dragging');
    initializePlaylistFromVisibleImages();
    const names = Array.from(LibraryList.querySelectorAll('.library-item:not(.library-item--skeleton)')).map(row => row.dataset.name).filter(Boolean);
    const originalIndexes = names.map(name => playlistOrder.indexOf(name)).filter(index => index >= 0);
    const insertAt = originalIndexes.length ? Math.min(...originalIndexes) : playlistOrder.length;
    const rest = playlistOrder.filter(name => !names.includes(name));
    rest.splice(insertAt, 0, ...names);
    playlistOrder = rest;
    playlistDirty = true;
    const byName = new Map(libraryImages.map(image => [image.name, image]));
    libraryImages = names.map(name => byName.get(name)).filter(Boolean);
    dragState = null;
    setStatus('Порядок изменён. Нажмите «Сохранить порядок», чтобы записать на SD.');
}

function resetLibraryState() {
    libraryOffset = 0;
    libraryTotal = 0;
    libraryTotalSize = 0;
    libraryImages = [];
    selectedImages.clear();
}

function loadLibrary(highlightName = "", append = false) {
    if (window.location.protocol === 'file:') {
        resetLibraryState();
        renderLibrary([], highlightName);
        return Promise.resolve();
    }
    if (libraryLoading) return Promise.resolve();
    libraryLoading = true;
    if (!append) {
        resetLibraryState();
        if (LibraryStats) LibraryStats.textContent = 'Загрузка…';
        renderLibrarySkeleton(libraryPageSize);
    }
    if (RefreshLibraryButton) RefreshLibraryButton.disabled = true;
    if (LoadMoreButton) LoadMoreButton.disabled = true;
    const previousOffset = append ? Math.max(libraryOffset - libraryPageSize, 0) : 0;
    if (append) {
        const skelCount = Math.max(libraryOffset - previousOffset, 1);
        prependLibrarySkeleton(skelCount);
    }
    const params = new URLSearchParams({
        offset: append ? String(previousOffset) : "last",
        limit: String(append ? Math.max(libraryOffset - previousOffset, 1) : libraryPageSize),
        q: libraryQuery
    });
    return fetch(`/AdminImages?${params.toString()}`, { cache: 'no-store' })
        .then(response => {
            if (!response.ok) throw new Error(`Request failed: ${response.status}`);
            return response.json();
        })
        .then(data => {
            const nextImages = (data.images || []).filter(image => isUsableLibraryImageName(image.name));
            libraryTotal = Number(data.total) || nextImages.length;
            libraryTotalSize = Number(data.totalSize) || 0;
            libraryOffset = Number(data.offset) || 0;
            libraryImages = append ? nextImages.concat(libraryImages) : nextImages;
            renderLibrary(libraryImages, highlightName);
            if (highlightName) scrollToLibraryImage(highlightName);
        })
        .catch(error => {
            console.error('Не удалось загрузить список изображений:', error);
            removeLibrarySkeletonRows();
            if (!append) renderLibrary([], highlightName);
            setStatus('Не удалось загрузить список изображений mode 1.', true);
        })
        .finally(() => {
            libraryLoading = false;
            if (RefreshLibraryButton) RefreshLibraryButton.disabled = false;
            updateLibraryStats();
        });
}

function loadMoreLibrary() {
    return loadLibrary("", true);
}

function handleLibrarySearch() {
    libraryQuery = LibrarySearchInput ? LibrarySearchInput.value.trim() : "";
    loadLibrary();
}

function deleteLibraryImage(name, skipConfirm = false) {
    if (!name || (!skipConfirm && !confirm(`Удалить ${name}?`))) return Promise.resolve();
    setStatus(`Удаляю ${name}...`);
    return fetch('/AdminImageDelete', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name })
    })
        .then(response => {
            if (!response.ok) throw new Error(`Request failed: ${response.status}`);
            selectedImages.delete(name);
            if (hasExplicitPlaylistOrder()) {
                const nextOrder = playlistOrder.filter(item => item !== name);
                if (nextOrder.length !== playlistOrder.length) {
                    playlistOrder = nextOrder;
                    playlistDirty = true;
                }
            }
            setStatus(`${name} удалён из коллекции mode 1.`);
        })
    .catch(error => {
        console.error('Не удалось удалить изображение:', error);
        setStatus('Не удалось удалить изображение с SD-карты.', true);
    });
}

function deleteSelectedImages() {
    const names = Array.from(selectedImages);
    if (!names.length || !confirm(`Удалить выбранные файлы (${names.length})?`)) return;
    names.reduce((chain, name) => chain.then(() => deleteLibraryImage(name, true)), Promise.resolve())
        .then(() => loadLibrary())
        .then(() => savePlaylistConfig());
}

function setLibraryImageNow(name, button) {
    if (!name) return;
    const originalText = button ? button.textContent : '';
    if (button) {
        button.disabled = true;
        button.textContent = 'Ставлю...';
    }
    if (!/\.bmp$/i.test(name)) {
        setStatus('Установить сейчас можно только BMP-файлы, подготовленные админкой.', true);
        if (button) {
            button.disabled = false;
            button.textContent = originalText;
        }
        return Promise.resolve();
    }

    setStatus(`Загружаю из коллекции и ставлю на экран: ${name}`);
    return fetch(`/AdminImage?name=${encodeURIComponent(name)}`, { cache: 'no-store' })
        .then(response => {
            if (!response.ok) throw new Error(`image fetch failed: ${response.status}`);
            return response.blob();
        })
        .then(blob => {
            const previewUrl = URL.createObjectURL(blob);
            const sourcePreview = document.getElementById('Image_Input');
            const processedPreview = document.getElementById('Image_Processed');
            let pendingLoads = 0;
            const revokePreviewUrl = () => {
                pendingLoads -= 1;
                if (pendingLoads <= 0) URL.revokeObjectURL(previewUrl);
            };
            if (sourcePreview) {
                pendingLoads += 1;
                sourcePreview.onload = revokePreviewUrl;
                sourcePreview.onerror = revokePreviewUrl;
                sourcePreview.src = previewUrl;
            }
            if (processedPreview) {
                pendingLoads += 1;
                processedPreview.onload = revokePreviewUrl;
                processedPreview.onerror = revokePreviewUrl;
                processedPreview.src = previewUrl;
            }
            if (!pendingLoads) URL.revokeObjectURL(previewUrl);
            return blob.arrayBuffer();
        })
        .then(buffer => {
            const pureBmpData = new Uint8Array(buffer);
            const modeByte = currentMode === "STA" ? 1 : 0;
            const finalData = new Uint8Array(1 + pureBmpData.length);
            finalData[0] = modeByte & 0xFF;
            finalData.set(pureBmpData, 1);

            return fetch('/dataUP', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/octet-stream'
                },
                body: new Blob([finalData], { type: 'application/octet-stream' })
            });
        })
        .then(response => {
            if (!response.ok) throw new Error(`dataUP failed: ${response.status}`);
            return response.text();
        })
        .then(() => {
            setStatus(`Изображение отправлено на экран: ${name}`);
            return saveLastImageConfig(name, true);
        })
        .catch(error => {
            console.error('Set now error:', error);
            setStatus('Не удалось установить изображение сейчас.', true);
        })
        .finally(() => {
            if (button) {
                button.disabled = false;
                button.textContent = originalText;
            }
        });
}

function loadAdminConfig() {
    if (window.location.protocol === 'file:') {
        return Promise.resolve();
    }
    return fetch('/AdminConfig', { cache: 'no-store' })
        .then(response => {
            if (!response.ok) throw new Error(`Request failed: ${response.status}`);
            return response.json();
        })
        .then(data => {
            if (Array.isArray(data.playlist)) {
                playlistOrder = data.playlist.filter(Boolean);
                playlistExplicit = playlistOrder.length > 0;
                playlistDirty = false;
            } else {
                playlistOrder = [];
                playlistExplicit = false;
                playlistDirty = false;
            }
            if (data.order === "random" || data.order === "sequential") {
                playlistMode = data.order;
                if (PlaylistModeInput) PlaylistModeInput.value = playlistMode;
            }
            playlistLast = data.next || data.last || "";
            updatePlaylistLastLabel();
            if (TimerInput && Number.isFinite(data.timer)) {
                TimerInput.value = data.timer;
            }
            if (data.schedule && typeof data.schedule === 'object') {
                scheduleConfig = { ...scheduleConfig, ...data.schedule };
                syncScheduleInputs();
            }
        })
        .catch(error => {
            console.error('Не удалось загрузить config.txt:', error);
        });
}

function syncScheduleInputs() {
    if (ScheduleEnabledInput) ScheduleEnabledInput.checked = Boolean(scheduleConfig.enabled);
    if (ScheduleDayStartInput) ScheduleDayStartInput.value = scheduleConfig.dayStart || "08:00";
    if (ScheduleNightStartInput) ScheduleNightStartInput.value = scheduleConfig.nightStart || "23:00";
    if (ScheduleDayTimerInput) ScheduleDayTimerInput.value = Number(scheduleConfig.dayTimer) || Number(TimerInput && TimerInput.value) || 300;
}

function normalizeScheduleTime(input, fallback) {
    const value = input && typeof input.value === 'string' ? input.value.trim() : "";
    return /^\d{2}:\d{2}$/.test(value) ? value : fallback;
}

function getValidScheduleDayTimer(timer) {
    const dayTimer = Number(ScheduleDayTimerInput && ScheduleDayTimerInput.value);
    if (!Number.isFinite(dayTimer) || dayTimer < 30 || dayTimer > 86400) {
        return timer;
    }
    return Math.round(dayTimer);
}

function getSchedulePayload(timer) {
    scheduleConfig = {
        enabled: Boolean(ScheduleEnabledInput && ScheduleEnabledInput.checked),
        dayStart: normalizeScheduleTime(ScheduleDayStartInput, "08:00"),
        nightStart: normalizeScheduleTime(ScheduleNightStartInput, "23:00"),
        dayTimer: getValidScheduleDayTimer(timer),
        nightMode: "sleep_until_day",
        timezoneOffsetMinutes: -new Date().getTimezoneOffset(),
        savedEpoch: Math.floor(Date.now() / 1000)
    };
    return scheduleConfig;
}

function saveAdminConfig(successMessage = 'Интервал mode 1 сохранён. Новое значение применится после следующего запуска mode 1.') {
    if (!TimerInput) return;
    const timer = Number(TimerInput.value);
    if (!Number.isFinite(timer) || timer < 30 || timer > 86400) {
        setStatus('Интервал должен быть от 30 до 86400 секунд.', true);
        return;
    }

    if (SaveConfigButton) SaveConfigButton.disabled = true;
    if (SaveScheduleButton) SaveScheduleButton.disabled = true;
    setStatus('Сохраняю config.txt...');
    fetch('/AdminConfig', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            timer,
            order: playlistMode,
            playlist: getPlaylistPayload(),
            last: playlistLast,
            schedule: getSchedulePayload(timer)
        })
    })
    .then(response => {
        if (!response.ok) throw new Error(`Request failed: ${response.status}`);
        return response.json();
    })
    .then(data => {
        if (TimerInput && Number.isFinite(data.timer)) {
            TimerInput.value = data.timer;
        }
        setSuccessStatus(successMessage);
    })
    .catch(error => {
        console.error('Не удалось сохранить config.txt:', error);
        setStatus('Не удалось сохранить config.txt.', true);
    })
    .finally(() => {
        if (SaveConfigButton) SaveConfigButton.disabled = false;
        if (SaveScheduleButton) SaveScheduleButton.disabled = false;
    });
}

function savePlaylistConfig() {
    if (PlaylistModeInput) {
        playlistMode = PlaylistModeInput.value === "random" ? "random" : "sequential";
    }
    if (playlistDirty && playlistOrder.length > 0) {
        playlistExplicit = true;
    }
    saveAdminConfig('Плейлист mode 1 сохранён.');
}

function saveScheduleConfig() {
    saveAdminConfig('Расписание mode 1 сохранено. Время браузера записано в config.txt.');
}

function saveLastImageConfig(name, markCurrent = false) {
    if (!name || window.location.protocol === 'file:') return Promise.resolve();
    playlistLast = name;
    updatePlaylistLastLabel();
    renderLibrary(libraryImages, name);
    const timer = Number(TimerInput && TimerInput.value) || 300;
    const payload = {
        timer,
        order: playlistMode,
        playlist: getPlaylistPayload(),
        last: playlistLast,
        current: markCurrent ? playlistLast : "",
        skipCurrentOnce: !!markCurrent,
        next: markCurrent ? "" : playlistLast,
        schedule: getSchedulePayload(timer)
    };
    return fetch('/AdminConfig', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
    }).then(response => {
        if (!response.ok) throw new Error(`AdminConfig failed: ${response.status}`);
        return response.json();
    }).catch(error => {
        console.warn('Не удалось сохранить last в config.txt:', error);
    });
}

function rebootIntoMode1() {
    if (!RebootMode1Button || window.location.protocol === 'file:') return;
    RebootMode1Button.disabled = true;
    setStatus('Переключаю рамку в mode 1...');
    const timer = Number(TimerInput && TimerInput.value) || 300;
    fetch('/AdminConfig', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            timer,
            order: playlistMode,
            playlist: getPlaylistPayload(),
            last: playlistLast,
            current: "",
            skipCurrentOnce: false,
            next: playlistLast,
            rebootMode1: true,
            schedule: getSchedulePayload(timer)
        })
    })
    .then(response => {
        if (!response.ok) throw new Error(`Request failed: ${response.status}`);
        return response.json();
    })
    .then(() => {
        setStatus('Рамка перезагружается в mode 1.');
    })
    .catch(error => {
        console.error('Не удалось перезагрузиться в mode 1:', error);
        setStatus('Не удалось перезагрузиться в mode 1.', true);
        RebootMode1Button.disabled = false;
    });
}

function getPowerText(battery) {
    if (!battery || !battery.available) return 'Батарея не обнаружена';
    if (battery.charging) return `Заряжается${battery.voltage_mv ? `, ${battery.voltage_mv} мВ` : ''}`;
    if (battery.discharging) return `Работает от батареи${battery.voltage_mv ? `, ${battery.voltage_mv} мВ` : ''}`;
    if (battery.vbus_good) return `Питание по USB${battery.voltage_mv ? `, ${battery.voltage_mv} мВ` : ''}`;
    return battery.charge_status ? battery.charge_status : 'Состояние питания неизвестно';
}

function renderDeviceStatus(data) {
    const battery = data.battery || {};
    const level = Number.isFinite(battery.level) ? battery.level : -1;
    const batteryFill = document.getElementById('battery_fill');

    if (battery.available && level >= 0) {
        setText('metric_battery', `${level}%`);
        if (batteryFill) {
            batteryFill.style.width = `${Math.max(0, Math.min(100, level))}%`;
            batteryFill.style.backgroundColor = level < 20 && battery.discharging ? '#b9362e' : '';
        }
    } else {
        setText('metric_battery', 'Нет данных');
        if (batteryFill) batteryFill.style.width = '0%';
    }
    setText('metric_power', getPowerText(battery));

    const network = data.network || {};
    const serverMode = network.mode === 'STA' ? 'STA' : 'AP';
    setText('metric_network', serverMode);
    setText('metric_address', serverMode === 'STA' ? 'Домашняя Wi-Fi сеть' : 'Точка доступа рамки');
    updateModeByValue(serverMode);
}

function loadDeviceStatus(showInlineError = false) {
    if (window.location.protocol === 'file:') {
        setText('metric_battery', 'Локальный файл');
        setText('metric_power', 'Состояние доступно только со страницы рамки');
        setText('metric_network', 'Недоступно');
        setText('metric_address', 'Откройте страницу с рамки');
        if (showInlineError) {
            setStatus('Откройте страницу с рамки, например http://192.168.4.1/index.html.', true);
        }
        return Promise.resolve();
    }
    if (RefreshStatusButton) RefreshStatusButton.disabled = true;
    return fetch('/DeviceStatus', { cache: 'no-store' })
        .then(response => {
            if (!response.ok) {
                throw new Error(`Request failed, status code:${response.status}`);
            }
            return response.json();
        })
        .then(renderDeviceStatus)
        .catch(error => {
            console.error('Не удалось получить состояние рамки:', error);
            setText('metric_battery', 'Недоступно');
            setText('metric_power', 'Прошивка без /DeviceStatus или нет связи');
            setText('metric_network', 'Недоступно');
            setText('metric_address', 'Проверьте подключение');
            if (showInlineError) {
                setStatus('Не удалось получить состояние рамки. Проверьте связь или обновите прошивку.', true);
            }
        })
        .finally(() => {
            if (RefreshStatusButton) RefreshStatusButton.disabled = false;
        });
}

function updateCropButton() {
    if (!CropButton) return;
    CropButton.textContent = cropMode === "cover" ? "Обрезка: вкл" : "Вписать целиком";
}

function syncCropInputs() {
    if (CropZoomInput) CropZoomInput.value = manualCrop.zoom;
    if (CropOffsetXInput) CropOffsetXInput.value = manualCrop.offsetX;
    if (CropOffsetYInput) CropOffsetYInput.value = manualCrop.offsetY;
}

function updateManualCropFromInputs() {
    manualCrop.zoom = Number(CropZoomInput && CropZoomInput.value) || 1;
    manualCrop.offsetX = Number(CropOffsetXInput && CropOffsetXInput.value) || 0;
    manualCrop.offsetY = Number(CropOffsetYInput && CropOffsetYInput.value) || 0;
    if (fileFlag) {
        processCurrentImage();
    }
}

function resetManualCrop() {
    manualCrop = { zoom: 1, offsetX: 0, offsetY: 0 };
    syncCropInputs();
    if (fileFlag) {
        processCurrentImage();
        setStatus('Ручная кадрировка сброшена.');
    }
}

function getImageOrientation(img) {
    return img && img.naturalWidth > img.naturalHeight ? "landscape" : "portrait";
}

function getOrientationLabel(orientation) {
    if (orientation === "landscape") return "альбомная";
    if (orientation === "portrait") return "портретная";
    return "авто";
}

function getEffectiveOrientation(img) {
    if (processPreset === "portrait") return "portrait";
    if (processPreset === "landscape") return "landscape";
    if (targetOrientation === "landscape" || targetOrientation === "portrait") {
        return targetOrientation;
    }
    return getImageOrientation(img);
}

function updateRotateButton() {
    if (!RotateButton) return;
    RotateButton.textContent = `Ориентация: ${getOrientationLabel(targetOrientation)}`;
}

function getTargetSize(img) {
    if (getEffectiveOrientation(img) === "landscape") {
        return { width: 800, height: 480 };
    }
    return { width: 480, height: 800 };
}

function getEdgeAverageColor(img) {
    if (!img || !img.naturalWidth || !img.naturalHeight) {
        return { r: 255, g: 255, b: 255 };
    }
    if (img._edgeAverageColor) return img._edgeAverageColor;

    const sampleCanvas = document.createElement('canvas');
    sampleCanvas.width = 32;
    sampleCanvas.height = 32;
    const sampleCtx = sampleCanvas.getContext('2d', { willReadFrequently: true });
    sampleCtx.drawImage(img, 0, 0, sampleCanvas.width, sampleCanvas.height);
    const { data } = sampleCtx.getImageData(0, 0, sampleCanvas.width, sampleCanvas.height);

    let r = 0;
    let g = 0;
    let b = 0;
    let count = 0;
    for (let y = 0; y < sampleCanvas.height; y++) {
        for (let x = 0; x < sampleCanvas.width; x++) {
            if (!(x < 3 || y < 3 || x >= sampleCanvas.width - 3 || y >= sampleCanvas.height - 3)) continue;
            const i = (y * sampleCanvas.width + x) * 4;
            r += data[i];
            g += data[i + 1];
            b += data[i + 2];
            count++;
        }
    }

    img._edgeAverageColor = count ? {
        r: Math.round(r / count),
        g: Math.round(g / count),
        b: Math.round(b / count)
    } : { r: 255, g: 255, b: 255 };
    return img._edgeAverageColor;
}

function drawImmersiveBackdrop(ctx, img, targetW, targetH) {
    const edge = getEdgeAverageColor(img);
    ctx.fillStyle = `rgb(${edge.r}, ${edge.g}, ${edge.b})`;
    ctx.fillRect(0, 0, targetW, targetH);

    const scale = Math.max(targetW / img.naturalWidth, targetH / img.naturalHeight);
    const drawW = img.naturalWidth * scale;
    const drawH = img.naturalHeight * scale;
    const drawX = (targetW - drawW) / 2;
    const drawY = (targetH - drawH) / 2;

    ctx.save();
    ctx.globalAlpha = 0.72;
    if ('filter' in ctx) {
        ctx.filter = 'blur(28px) saturate(1.06) brightness(0.92)';
    }
    ctx.drawImage(img, drawX, drawY, drawW, drawH);
    ctx.restore();

    ctx.fillStyle = 'rgba(255, 250, 240, 0.08)';
    ctx.fillRect(0, 0, targetW, targetH);
}

function drawPreparedImage(ctx, img, targetW, targetH) {
    const baseScale = cropMode === "cover"
        ? Math.max(targetW / img.naturalWidth, targetH / img.naturalHeight)
        : Math.min(targetW / img.naturalWidth, targetH / img.naturalHeight);
    const scale = baseScale * Math.max(0.1, manualCrop.zoom);
    const drawW = img.naturalWidth * scale;
    const drawH = img.naturalHeight * scale;
    const hasLetterbox = drawW < targetW - 0.5 || drawH < targetH - 0.5;
    if (immersiveBackground && hasLetterbox) {
        drawImmersiveBackdrop(ctx, img, targetW, targetH);
    } else {
        ctx.fillStyle = "#ffffff";
        ctx.fillRect(0, 0, targetW, targetH);
    }
    const maxOffsetX = Math.abs(drawW - targetW) / 2;
    const maxOffsetY = Math.abs(drawH - targetH) / 2;
    const drawX = (targetW - drawW) / 2 + manualCrop.offsetX * maxOffsetX;
    const drawY = (targetH - drawH) / 2 + manualCrop.offsetY * maxOffsetY;
    ctx.drawImage(img, drawX, drawY, drawW, drawH);
}

function applyImagePreset(canvas, ctx) {
    const preset = processPreset;
    if (preset !== "portrait" && preset !== "landscape" && preset !== "high_contrast") {
        return;
    }
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    const contrast = preset === "high_contrast" ? 1.28 : 1.10;
    const saturation = preset === "high_contrast" ? 1.18 : 1.06;
    for (let i = 0; i < data.length; i += 4) {
        let r = (data[i] - 128) * contrast + 128;
        let g = (data[i + 1] - 128) * contrast + 128;
        let b = (data[i + 2] - 128) * contrast + 128;
        const gray = r * 0.299 + g * 0.587 + b * 0.114;
        r = gray + (r - gray) * saturation;
        g = gray + (g - gray) * saturation;
        b = gray + (b - gray) * saturation;
        data[i] = Math.max(0, Math.min(255, r));
        data[i + 1] = Math.max(0, Math.min(255, g));
        data[i + 2] = Math.max(0, Math.min(255, b));
    }
    ctx.putImageData(imageData, 0, 0);
}

function findNearestColorIndex(r, g, b) {
    let minDist = Infinity;
    let nearestIdx = 0;
    for (let i = 0; i < palette.length; i++) {
        if (palette[i] === null) continue;
        const pr = palette[i][0];
        const pg = palette[i][1];
        const pb = palette[i][2];
        const dist = (r - pr) ** 2 + (g - pg) ** 2 + (b - pb) ** 2;
        if (dist < minDist) {
            minDist = dist;
            nearestIdx = i;
        }
    }
    return nearestIdx;
}

function quantizeCanvas(canvas, ctx) {
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    const idxArr = new Uint8Array(canvas.width * canvas.height);
    for (let y = 0; y < canvas.height; y++) {
        for (let x = 0; x < canvas.width; x++) {
            const i = (y * canvas.width + x) * 4;
            const idx = findNearestColorIndex(data[i], data[i + 1], data[i + 2]);
            const [newR, newG, newB] = palette[idx];
            data[i] = newR;
            data[i + 1] = newG;
            data[i + 2] = newB;
            idxArr[y * canvas.width + x] = idx;
        }
    }
    ctx.putImageData(imageData, 0, 0);
    window._lastImageIndexArray = idxArr;
}

function ditherCanvas(canvas, ctx, strength = 1) {
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    const idxArr = new Uint8Array(canvas.width * canvas.height);

    for (let y = 0; y < canvas.height; y++) {
        for (let x = 0; x < canvas.width; x++) {
            const i = (y * canvas.width + x) * 4;
            const oldR = data[i];
            const oldG = data[i + 1];
            const oldB = data[i + 2];
            const idx = findNearestColorIndex(oldR, oldG, oldB);
            const [newR, newG, newB] = palette[idx];

            data[i] = newR;
            data[i + 1] = newG;
            data[i + 2] = newB;
            idxArr[y * canvas.width + x] = idx;

            const errR = oldR - newR;
            const errG = oldG - newG;
            const errB = oldB - newB;

            if (x + 1 < canvas.width) {
                let j = i + 4;
                data[j] = Math.max(0, Math.min(255, data[j] + errR * 7 / 16 * strength));
                data[j + 1] = Math.max(0, Math.min(255, data[j + 1] + errG * 7 / 16 * strength));
                data[j + 2] = Math.max(0, Math.min(255, data[j + 2] + errB * 7 / 16 * strength));
            }
            if (x > 0 && y + 1 < canvas.height) {
                let j = i + (canvas.width - 1) * 4;
                data[j] = Math.max(0, Math.min(255, data[j] + errR * 3 / 16 * strength));
                data[j + 1] = Math.max(0, Math.min(255, data[j + 1] + errG * 3 / 16 * strength));
                data[j + 2] = Math.max(0, Math.min(255, data[j + 2] + errB * 3 / 16 * strength));
            }
            if (y + 1 < canvas.height) {
                let j = i + canvas.width * 4;
                data[j] = Math.max(0, Math.min(255, data[j] + errR * 5 / 16 * strength));
                data[j + 1] = Math.max(0, Math.min(255, data[j + 1] + errG * 5 / 16 * strength));
                data[j + 2] = Math.max(0, Math.min(255, data[j + 2] + errB * 5 / 16 * strength));
            }
            if (x + 1 < canvas.width && y + 1 < canvas.height) {
                let j = i + (canvas.width + 1) * 4;
                data[j] = Math.max(0, Math.min(255, data[j] + errR * 1 / 16 * strength));
                data[j + 1] = Math.max(0, Math.min(255, data[j + 1] + errG * 1 / 16 * strength));
                data[j + 2] = Math.max(0, Math.min(255, data[j + 2] + errB * 1 / 16 * strength));
            }
        }
    }

    ctx.putImageData(imageData, 0, 0);
    window._lastImageIndexArray = idxArr;
}

function renderProcessedPreview() {
    const processedImg = document.getElementById('Image_Processed');
    if (!processedImg || !processedBase64) return;
    processedImg.src = processedBase64;
}

function processCurrentImage() {
    if (!ImageSys || !ImageSys.complete || !ImageSys.naturalWidth) return;

    const { width: targetW, height: targetH } = getTargetSize(ImageSys);
    const canvas = document.createElement('canvas');
    canvas.width = targetW;
    canvas.height = targetH;
    const ctx = canvas.getContext('2d');

    drawPreparedImage(ctx, ImageSys, targetW, targetH);
    applyImagePreset(canvas, ctx);
    if (processPreset === "no_dither") {
        quantizeCanvas(canvas, ctx);
    } else {
        ditherCanvas(canvas, ctx, processPreset === "soft_dither" ? 0.45 : 1);
    }

    processedBase64 = canvas.toDataURL();
    renderProcessedPreview();

    const cropText = cropMode === "cover"
        ? "с центрированной обрезкой"
        : (immersiveBackground ? "с иммерсивным фоном" : "с белыми полями");
    setStatus(`Изображение подготовлено ${cropText}: ${canvas.width}x${canvas.height}. Можно отправлять.`);
}

function updateModeByValue(targetMode) {
    const validModes = ['AP', 'STA'];
    if (!validModes.includes(targetMode)) {
        console.warn('Invalid mode value. Using default AP mode.');
        targetMode = 'AP';
    }

    const activeButton = document.querySelector(`a[data-mode="${targetMode}"]`);
    if (activeButton) {
        modeButtons.forEach(btn => btn.classList.remove('active'));
        activeButton.classList.add('active');
        currentMode = targetMode;
        updateTips();
    }
}

function initializeMode() {
    updateModeByValue('AP');
}

function updateTips() {
    tips.forEach(tip => tip.classList.remove('d-none'));
    if (currentMode === "AP") {
        document.getElementById('tips-STA')?.classList.add('d-none');
    } else {
        document.getElementById('tips-AP')?.classList.add('d-none');
    }
}

