function InPutButton_Even() {
    FileInput.click();
}

function FileInput_Even(e) {
    const file = e.target.files[0];
    if (!file) {
        updateInputStageState(InputFileLabel ? InputFileLabel.textContent : "");
        return;
    }
    if (!file.type.startsWith("image/")) {
        setErrorStatus("Выберите файл изображения.");
        return;
    }

    fileFlag = 0;
    processedBase64 = "";
    targetOrientation = "auto";
    manualCrop = { zoom: 1, offsetX: 0, offsetY: 0 };
    updateRotateButton();
    syncCropInputs();
    showScreen('prepare');
    currentFileBaseName = file.name.replace(/\.[^.]+$/, '').replace(/[^a-zA-Z0-9_-]+/g, '_').slice(0, 32) || 'image';
    updateInputStageState(file.name);
    setStatus("Загружаю и подготавливаю изображение...");
    const url = URL.createObjectURL(file);
    ImageSys.src = url;
    ImageSys.addEventListener('load', function revoke() {
        URL.revokeObjectURL(url);
        ImageSys.removeEventListener('load', revoke);
    });
    fileFlag = 1;
    updateInputStageState(file.name);
    e.target.value = '';
}

function CropButton_Even() {
    cropMode = cropMode === "cover" ? "contain" : "cover";
    updateCropButton();
    if (!fileFlag) {
        setStatus(cropMode === "cover" ? "Обрезка будет применена к следующему изображению." : "Следующее изображение будет вписано целиком.");
        return;
    }
    setStatus("Пересчитываю изображение под рамку...");
    processCurrentImage();
}

function RotateButton_Even() {
    if (!fileFlag) {
        setErrorStatus("Сначала выберите изображение.");
        return;
    }
    const current = getEffectiveOrientation(ImageSys);
    targetOrientation = current === "landscape" ? "portrait" : "landscape";
    updateRotateButton();
    setStatus(`Пересчитываю под ${getOrientationLabel(targetOrientation)} ориентацию...`);
    processCurrentImage();
}

function createBMPUint8Array(imageData, width, height) {
    const bytesPerPixel = 3;
    const rowSize = Math.ceil((bytesPerPixel * width) / 4) * 4;
    const pixelDataSize = rowSize * height;
    const bmpFileHeaderSize = 14;
    const bmpInfoHeaderSize = 40;
    const totalBmpSize = bmpFileHeaderSize + bmpInfoHeaderSize + pixelDataSize;

    const bmpData = new Uint8Array(totalBmpSize);
    const dataView = new DataView(bmpData.buffer);

    dataView.setUint8(0, 0x42);
    dataView.setUint8(1, 0x4D);
    dataView.setUint32(2, totalBmpSize, true);
    dataView.setUint16(6, 0, true);
    dataView.setUint16(8, 0, true);
    dataView.setUint32(10, bmpFileHeaderSize + bmpInfoHeaderSize, true);

    dataView.setUint32(14, bmpInfoHeaderSize, true);
    dataView.setUint32(18, width, true);
    dataView.setUint32(22, height, true);
    dataView.setUint16(26, 1, true);
    dataView.setUint16(28, bytesPerPixel * 8, true);
    dataView.setUint32(30, 0, true);
    dataView.setUint32(34, pixelDataSize, true);
    dataView.setUint32(38, 72, true);
    dataView.setUint32(42, 72, true);
    dataView.setUint32(46, 0, true);
    dataView.setUint32(50, 0, true);

    let pixelOffset = bmpFileHeaderSize + bmpInfoHeaderSize;
    const rgba = imageData.data;

    for (let y = height - 1; y >= 0; y--) {
        let rowOffset = 0;
        for (let x = 0; x < width; x++) {
            const rgbaIndex = (y * width + x) * 4;
            bmpData[pixelOffset + rowOffset] = rgba[rgbaIndex + 2];
            bmpData[pixelOffset + rowOffset + 1] = rgba[rgbaIndex + 1];
            bmpData[pixelOffset + rowOffset + 2] = rgba[rgbaIndex];
            rowOffset += bytesPerPixel;
        }
        while (rowOffset % 4 !== 0) {
            bmpData[pixelOffset + rowOffset] = 0;
            rowOffset++;
        }
        pixelOffset += rowSize;
    }

    return bmpData;
}

function createPreparedBmp(callback) {
    if (!processedBase64) {
        callback(null);
        return;
    }

    const tempCanvas = document.createElement('canvas');
    const img = new window.Image();

    img.onload = function () {
        try {
            if (!img.naturalWidth || !img.naturalHeight) throw new Error('decoded image has invalid dimensions');
            tempCanvas.width = img.naturalWidth;
            tempCanvas.height = img.naturalHeight;

            const ctx = tempCanvas.getContext('2d');
            if (!ctx) throw new Error('canvas context unavailable');
            ctx.drawImage(img, 0, 0);

            const imageData = ctx.getImageData(0, 0, tempCanvas.width, tempCanvas.height);
            callback(createBMPUint8Array(imageData, tempCanvas.width, tempCanvas.height));
        } catch (error) {
            console.error('BMP preparation failed:', error);
            callback(null);
        }
    };
    img.onerror = function () {
        callback(null);
    };

    img.src = processedBase64;
}

function createPreparedThumb(callback) {
    if (!processedBase64) return;

    const img = new window.Image();
    img.onload = function () {
        const canvas = drawThumbnailToCanvas(img);
        canvas.toBlob(callback, 'image/jpeg', 0.88);
    };
    img.onerror = function () {
        callback(null);
    };
    img.src = processedBase64;
}

function SaveLibraryButton_Even() {
    if (!fileFlag) {
        setErrorStatus("Сначала выберите изображение.");
        return;
    }
    if (!processedBase64) return;

    setLibraryBusy(true);
    setStatus("Сохраняю изображение в папку mode 1...");

    createPreparedBmp(function (pureBmpData) {
        if (!pureBmpData) {
            setErrorStatus("Не удалось подготовить BMP для сохранения.");
            setLibraryBusy(false);
            return;
        }
        const filename = `${currentFileBaseName}_${Date.now()}.bmp`;
        fetch(`/AdminImageUpload?name=${filename}`, {
            method: "POST",
            headers: {
                "Content-Type": "application/octet-stream"
            },
            body: new Blob([pureBmpData], { type: 'application/octet-stream' })
        })
        .then(response => {
            if (!response.ok) throw new Error(`Request failed: ${response.status}`);
            return response.text();
        })
        .then(text => {
            let data = {};
            try {
                data = JSON.parse(text);
            } catch (error) {
                const match = text.match(/"name":"([^"]+)"/);
                if (match) data.name = match[1];
            }
            const savedName = data.name || filename;
            addToPlaylistIfExplicit(savedName);
            libraryQuery = "";
            if (LibrarySearchInput) LibrarySearchInput.value = "";
            showScreen('collection');
            setStatus(`${savedName} сохранён в коллекцию mode 1. Готовлю превью...`);
            return new Promise(resolve => {
                createPreparedThumb(function (thumbBlob) {
                    if (!thumbBlob) {
                        resolve();
                        return;
                    }
                    fetch(`/AdminThumbUpload?name=${encodeURIComponent(savedName)}`, {
                        method: "POST",
                        headers: {
                            "Content-Type": "image/jpeg"
                        },
                        body: thumbBlob
                    }).catch(error => {
                        console.warn("Thumbnail upload error:", error);
                    }).finally(resolve);
                });
            }).then(() => {
                setSuccessStatus(`${savedName} сохранён в коллекцию mode 1.`, { duration: 4200 });
                return loadLibrary(savedName);
            });
        })
        .catch(error => {
            console.error("Library upload error:", error);
            setErrorStatus("Не удалось сохранить изображение в коллекцию mode 1.");
        })
        .finally(() => {
            setLibraryBusy(false);
        });
    });
}

function SendButton_Even() {
    if (!fileFlag) {
        setErrorStatus("Сначала выберите изображение.");
        return;
    }
    if (!processedBase64) return;

    setSendBusy(true);
    setStatus("Готовлю BMP и отправляю на рамку...");

    const modeByte = currentMode === "STA" ? 1 : 0;
    createPreparedBmp(function (pureBmpData) {
        if (!pureBmpData) {
            setErrorStatus("Не удалось подготовить BMP для отправки.");
            setSendBusy(false);
            return;
        }
        const finalData = new Uint8Array(1 + pureBmpData.length);
        finalData[0] = modeByte & 0xFF;
        finalData.set(pureBmpData, 1);

        fetch("/dataUP", {
            method: "POST",
            headers: {
                "Content-Type": "application/octet-stream"
            },
            body: new Blob([finalData], { type: 'application/octet-stream' })
        })
        .then(res => {
            if (res.ok && res.status === 200) {
                return res.text().then(() => {
                    setSuccessStatus("Изображение успешно отправлено. Дождитесь полного обновления экрана.", { duration: 4600 });
                });
            }
            return res.text().then(errorMsg => {
                throw new Error(`Ошибка отправки: ${res.status})${errorMsg ? `: ${errorMsg}` : ''}`);
            }).catch(() => {
                throw new Error(`Ошибка отправки: ${res.status})`);
            });
        }).catch(err => {
            console.error("Upload error:", err);
            setErrorStatus("Не удалось отправить изображение. Проверьте подключение к рамке.");
        }).finally(() => {
            setSendBusy(false);
        });
    });
}

function bindModeButtonEvents() {
    modeButtons.forEach(button => {
        button.addEventListener('click', function(event) {
            event.preventDefault();
            updateModeByValue(this.dataset.mode);
        });
    });
}

document.addEventListener('DOMContentLoaded', function() {
    modeButtons = document.querySelectorAll('a[data-mode]');
    tips = document.querySelectorAll('#tips > div');
    appNavButtons = document.querySelectorAll('.app-nav-button');
    appScreens = document.querySelectorAll('.app-screen');

    bindModeButtonEvents();
    Even_init();
    if (UploadStatus) {
        setInitialStatus("Готово к выбору изображения.");
    }
    loadAdminConfig().finally(loadLibrary);

    fetch('/NetWorkStatus')
        .then(response => {
            if (!response.ok) {
                throw new Error(`Request failed, status code:${response.status}`);
            }
            return response.text();
        })
        .then(data => {
            let serverMode = 'AP';
            const serverCode = parseInt(data);
            if (!isNaN(serverCode)) {
                serverMode = serverCode === 1 ? 'STA' : 'AP';
            }
            updateModeByValue(serverMode);
        })
        .catch(error => {
            console.error('Не удалось получить режим сети. Используется AP по умолчанию:', error);
            initializeMode();
        });

    if (DeviceStatusPanel && DeviceStatusPanel.open) {
        loadDeviceStatus();
        statusRefreshTimer = setInterval(loadDeviceStatus, 30000);
    }
});
